def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_pitfalls(nums, target):
    if len(nums) < 2:
        return "No solution: not enough numbers"
    if len(set(nums)) < len(nums):
        return "No solution: indices may be reused"

# Example usage
result = solve([1, 2, 3, 4, 5], 9)
pitfall_check = check_pitfalls([1, 2, 3, 4, 5], 9)
print(result)  # Output should be (3, 4)
print(pitfall_check)  # Should not indicate any pitfalls
